from enum import Enum
from dataclasses import dataclass
import time


class VehicleType(Enum):
    MOTORCYCLE = 1
    CAR = 2
    TRUCK = 3


class SpotType(Enum):
    SMALL = 1   # fits motorcycle
    COMPACT = 2  # fits motorcycle, car
    LARGE = 3   # fits motorcycle, car, truck


# which spot types can hold which vehicle (smallest-first order matters for allocation)
FITS = {
    VehicleType.MOTORCYCLE: [SpotType.SMALL, SpotType.COMPACT, SpotType.LARGE],
    VehicleType.CAR:        [SpotType.COMPACT, SpotType.LARGE],
    VehicleType.TRUCK:      [SpotType.LARGE],
}


class Vehicle:
    def __init__(self, plate: str, vtype: VehicleType):
        self.plate = plate
        self.vtype = vtype


class ParkingSpot:
    def __init__(self, spot_id: str, stype: SpotType):
        self.spot_id = spot_id
        self.stype = stype
        self.vehicle = None  # occupant

    @property
    def is_free(self) -> bool:
        return self.vehicle is None


@dataclass
class Ticket:
    ticket_id: str
    plate: str
    spot_id: str
    entry_ts: float

    def __post_init__(self):
        self.exit_ts = None
